#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
double a[100010];
struct node{
    double sum, lazy;
};
node t1[400010], t2[400010];
void pushup (int rt) {
    t1[rt].sum = t1[rt << 1].sum + t1[rt << 1 | 1].sum;	
    t2[rt].sum = t2[rt << 1].sum + t2[rt << 1 | 1].sum;	
}
void pushdown (int rt, int l, int r) {
    int mid = (l + r) >> 1;
    t2[rt << 1].lazy += t2[rt].lazy;
    t2[rt << 1].sum += t1[rt << 1].sum * (t2[rt].lazy * 2) + (mid - l + 1) * (t2[rt].lazy * t2[rt].lazy);
    t2[rt << 1 | 1].lazy += t2[rt].lazy;
    t2[rt << 1 | 1].sum += t1[rt << 1 | 1].sum * (t2[rt].lazy * 2) + (r - mid) * (t2[rt].lazy * t2[rt].lazy);
    t2[rt].lazy = 0;
    t1[rt << 1].lazy += t1[rt].lazy;
    t1[rt << 1].sum += (mid - l + 1) * t1[rt].lazy;
    t1[rt << 1 | 1].lazy += t1[rt].lazy;
    t1[rt << 1 | 1].sum += (r - mid) * t1[rt].lazy;	
    t1[rt].lazy = 0;
}
void build (int rt, int l, int r) {
    if (l == r) {
        t1[rt].sum = a[l];
        t2[rt].sum = a[l] * a[l];
        return;	
    }
    int mid = (l + r) >> 1;
    build(rt << 1, l, mid);
    build(rt << 1 | 1, mid + 1, r);
    pushup(rt);
}
double query (node tree[], int rt, int l, int r, int x, int y) {
    if (x <= l && r <= y) {
    	return tree[rt].sum;
	}
    int mid = (l + r) >> 1;
    if (tree[rt].lazy) {
    	pushdown (rt, l, r);
	}
    double ans = 0;
    if (x <= mid) {
    	ans = ans + query(tree, rt << 1, l, mid, x, y);
	}
    if (y > mid) {
    	ans = ans + query(tree, rt << 1 | 1, mid + 1, r, x, y);
	}
    pushup(rt);
    return ans;
}
void modify (int rt, int l, int r, int x, int y , double z) {
    if (x <= l && r <= y) {
        t2[rt].lazy += z;
        t2[rt].sum += t1[rt].sum * (z * 2) + (r - l + 1) * (z * z);
        t1[rt].lazy += z;
        t1[rt].sum += (r - l + 1) * z;
        return;
    }
    if (t1[rt].lazy || t2[rt].lazy) {
    	pushdown(rt, l, r); 
	}
    int mid = (l + r) >> 1; 
    if (x <= mid) {
    	modify(rt << 1, l, mid, x, y, z);
	}
    if (y > mid) {
    	modify(rt << 1 | 1, mid + 1, r, x, y, z);
	}
    pushup(rt);
}
int n, m, opt;
signed main() {
	cin >> n >> m;
    for (int i = 1;i <= n;i ++) {
        cin >> a[i];
    }
    build(1, 1, n);
    while (m--) {
    	cin >> opt;
        if(opt == 1) {
            int x, y;
            double z;
            cin >> x >> y >> z;
            modify (1, 1, n, x, y, z);
        }
        if(opt == 2) {
            int x, y;
            cin >> x >> y;
            cout << fixed << setprecision(4) << query(t1, 1, 1, n, x, y) / ((y - x + 1) * 1.0) << '\n';;
        }
        if(opt == 3) {
            int x, y;
            cin >> x >> y;
            cout << fixed << setprecision(4) << (query(t2, 1, 1, n, x, y) / ((y - x + 1) * 1.0)) - (query(t1, 1, 1, n, x, y) / ((y - x + 1) * 1.0)) * (query(t1, 1, 1, n, x, y) / ((y - x + 1) * 1.0)) << '\n';
        }
    }
    return 0;
}
